#nullable enable // autogenerated

using System.Collections.Generic;
using ExpressionEvaluator;
using MVZ2.Managers;
using PVZEngine;

namespace MVZ2.Metas
{
    public class AlmanacVariableContext : IAttributeContext
    {
        public MainManager main;
        public string currentDefinitionType;
        public NamespaceID currentDefinitionID;
        public AlmanacMetaEntry currentAlmanacEntry;
        public HashSet<NamespaceID> globalCallStack = new();
        public HashSet<string> localCallStack = new();

        public AlmanacVariableContext(MainManager main, string currentDefinitionType, NamespaceID currentDefinitionID, AlmanacMetaEntry currentAlmanacEntry)
        {
            this.main = main;
            this.currentDefinitionType = currentDefinitionType;
            this.currentDefinitionID = currentDefinitionID;
            this.currentAlmanacEntry = currentAlmanacEntry;
        }

        object? IAttributeContext.EvaluateVariable(string name)
        {
            return null;
        }

        object? IAttributeContext.EvaluateFunction(string name, object?[] args)
        {
            return AlmanacVariableFunctions.EvaluateFunctions(this, name, args);
        }
    }
}
